/**
 * Clears the timed-out warning for a session by stamping `dismissedAt` on every still-failed sweeper-timeout turn. Transcript and per-turn status are left intact. If a *new* round in the same session later times out, the warning re-appears for that new round.
 * @summary Acknowledge a stuck/timed-out round you don't plan to resume
 */
export const DismissStudyGroupTimeoutParams = zod.object({
  id: zod.coerce.number(),
});

export const DismissStudyGroupTimeoutResponse = zod.object({
  dismissed: zod
    .number()
    .describe("How many timed-out turn rows were marked dismissed."),
});

/**
 * Clears the timed-out warning across every session by stamping `dismissedAt` on every still-failed sweeper-timeout turn. Returns the number of turn rows dismissed and the number of distinct sessions that were cleared. Transcripts and per-turn status are left intact.
 * @summary Bulk-acknowledge every currently stuck study-group round
 */
export const DismissAllStudyGroupTimeoutsResponse = zod.object({
  dismissed: zod
    .number()
    .describe(
      "Total number of timed-out turn rows marked dismissed across all sessions.",
    ),
  sessionsCleared: zod
    .number()
    .describe("Number of distinct sessions whose stuck warning was cleared."),
});

/**
 * Server-side fan-out version of `POST /study-group/sessions/{id}/round` with `{retry:true}`. Finds every session with at least one undismissed sweeper-timeout turn, kicks off resume for each in the background with a small concurrency cap, and returns a summary immediately. The dashboard can poll the sessions list to watch stuck rows clear instead of holding a long-lived browser tab open over per-session SSE streams.
 * @summary Bulk-resume every currently stuck study-group round
 */
export const ResumeAllStudyGroupTimeoutsResponse = zod.object({
  started: zod
    .number()
    .describe(
      "Number of stuck sessions handed off to a background resume worker.",
    ),
  skipped: zod
    .array(
      zod.object({
        sessionId: zod.number(),
        title: zod.string(),
        reason: zod.string(),
      }),
    )
    .describe(
      "Sessions that couldn't be resumed at all (e.g., session row missing or topic missing). The dashboard surfaces these as a precise error.",
    ),
});

/**
 * Reverses `dismissStudyGroupTimeout` by clearing `dismissedAt` on every still-failed sweeper-timeout turn for the session. The dashboard banner and sidebar warning re-appear; transcript and per-turn status are unchanged.
 * @summary Undo a previous dismissal so the timed-out warning comes back
 */
export const RestoreStudyGroupTimeoutParams = zod.object({
  id: zod.coerce.number(),
});

export const RestoreStudyGroupTimeoutResponse = zod.object({
  restored: zod
    .number()
    .describe(
      "How many previously-dismissed timed-out turn rows had their dismissedAt cleared.",
    ),
});

